starterCode.css:
body { font-family: system-ui, sans-serif; padding: 24px; background: #f4f6f8; }
.dashboard { max-width: 760px; margin: auto; }
button { padding: 10px 14px; }
.metricas { display: grid; grid-template-columns: repeat(3, 1fr); gap: 10px; margin: 16px 0; }
article { background: white; border: 1px solid #d8dee8; padding: 14px; border-radius: 8px; display: grid; gap: 4px; }
strong { font-size: 2rem; }
ol { background: white; padding: 18px 18px 18px 38px; border: 1px solid #d8dee8; }
